817:     private void failBatch(
818:         ProducerBatch batch,
819:         RuntimeException topLevelException,
820:         Function<Integer, RuntimeException> recordExceptions,
821:         boolean adjustSequenceNumbers
822:     ) {
823:         this.sensors.recordErrors(batch.topicPartition.topic(), batch.recordCount);
824: 
825:         if (batch.completeExceptionally(topLevelException, recordExceptions)) {
826:             if (transactionManager != null) {
827:                 try {
828:                     // This call can throw an exception in the rare case that there's an invalid state transition
829:                     // attempted. Catch these so as not to interfere with the rest of the logic.
830:                     transactionManager.handleFailedBatch(batch, topLevelException, adjustSequenceNumbers);
831:                 } catch (Exception e) {
832:                     log.debug("Encountered error when transaction manager was handling a failed batch", e);
833:                 }
834:             }
835:             maybeRemoveAndDeallocateBatch(batch);
836:         }
837:     }
